def _normalize(code: str) -> str:
    """Normalize an ICD-10 code for comparison: strip dots/whitespace, uppercase.

    Canvas stores ICD-10 condition codes undotted (e.g. "E119"); the ACCESS value
    sets use dotted codes (e.g. "E11.9"). Normalizing both sides lets us match.
    """
    return code.replace(".", "").replace(" ", "").upper()


# Normalized (undotted) -> canonical (dotted) per track, built once at import.
_NORMALIZED_TO_CANONICAL: dict[str, dict[str, str]] = {
    track: {_normalize(c): c for c in codes}
    for track, codes in TRACK_DIAGNOSIS_CODES.items()
}


def canonical_code_for_track(track: str, raw_code: str) -> str | None:
    """Return the canonical dotted ICD-10 code if raw_code qualifies for the track.

    Accepts a code in either dotted or undotted form and returns the exact dotted
    string the ACCESS value set publishes (so it validates against the track-specific
    Condition profile), or None if the code is not a qualifying diagnosis for the track.
    """
    lookup = _NORMALIZED_TO_CANONICAL.get(track)
    if not lookup:
        return None
    return lookup.get(_normalize(raw_code))
